{
  "integrative": {
    "title": "Integrative Close: Practical Installation Calculation",
    "objective": "Synthesize formula transposition, percentage safety factors, and trigonometry within a single electrical installation scenario.",
    "retrievalTextLines": [
      "To solve complex site problems, you must combine multiple mathematical tools.",
      "First, use transposition to rearrange your base formulas, remembering to 'change the side, change the sign' to isolate your unknown value.",
      "Second, apply percentages to account for safety factors or tolerances—this is your 'parts per hundred' calculation.",
      "Finally, use Pythagoras’ Theorem for physical measurements, ensuring you square the sides before adding them and taking the square root at the very end."
    ],
    "questionText": "You are installing a heavy-duty heater. 1) Transpose the power formula (P = V × I) to find the formula for Current (I). 2) If the heater is rated at 4600W and the voltage is 230V, calculate the current. 3) For safety, the circuit must be rated at 120% of this current; calculate the required capacity. 4) The cable for this heater must run 8 meters across a ceiling and 6 meters down a wall; calculate the diagonal length of the cable run using Pythagoras.",
    "answerGuidance": [
      "Transposed formula: I = P / V",
      "Calculated Current: 20 Amps (4600 / 230)",
      "Safety Capacity: 24 Amps (20 x 1.20)",
      "Diagonal Cable Length: 10 meters (Square root of 8 squared + 6 squared, or √100)"
    ],
    "hint": "For the transposition, move V by dividing. For the cable run, remember that 8 squared is 64 and 6 squared is 36; add them before finding the square root."
  }
}

